&lt;ul data-start=&quot;1136&quot; data-end=&quot;1521&quot;&gt;
&lt;li data-start=&quot;1136&quot; data-end=&quot;1190&quot;&gt;
&lt;p data-start=&quot;1138&quot; data-end=&quot;1190&quot;&gt;Pressure wash and shampoo the exterior of vehicles&lt;/p&gt;
&lt;/li&gt;
&lt;li data-start=&quot;1191&quot; data-end=&quot;1246&quot;&gt;
&lt;p data-start=&quot;1193&quot; data-end=&quot;1246&quot;&gt;Steam, extract, and vacuum the interior of vehicles&lt;/p&gt;
&lt;/li&gt;
&lt;li data-start=&quot;1247&quot; data-end=&quot;1283&quot;&gt;
&lt;p data-start=&quot;1249&quot; data-end=&quot;1283&quot;&gt;Polish swirl marks and scratches&lt;/p&gt;
&lt;/li&gt;
&lt;li data-start=&quot;1284&quot; data-end=&quot;1330&quot;&gt;
&lt;p data-start=&quot;1286&quot; data-end=&quot;1330&quot;&gt;Dress tires and maintain exterior finishes&lt;/p&gt;
&lt;/li&gt;
&lt;li data-start=&quot;1331&quot; data-end=&quot;1396&quot;&gt;
&lt;p data-start=&quot;1333&quot; data-end=&quot;1396&quot;&gt;Proactively monitor and maintain detailing supplies and tools&lt;/p&gt;
&lt;/li&gt;
&lt;li data-start=&quot;1397&quot; data-end=&quot;1446&quot;&gt;
&lt;p data-start=&quot;1399&quot; data-end=&quot;1446&quot;&gt;Continuously help improve detailing processes&lt;/p&gt;
&lt;/li&gt;
&lt;li data-start=&quot;1447&quot; data-end=&quot;1521&quot;&gt;
